diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index f9155cc66031..13621c6d443a 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -2262,6 +2262,62 @@ static Instruction *foldSubOfMinMax(BinaryOperator &I,
     Function *F = Intrinsic::getOrInsertDeclaration(I.getModule(), InvID, Ty);
     return CallInst::Create(F, {Op0, Z});
   }
+  // sub(smin(add nsw X, 1), smin(X, Y)) --> select(icmp slt X, Y), 1, 0
+  // sub(smax(add nsw X, 1), smax(X, Y)) --> select(icmp sge X, Y), 1, 0
+  // sub(umin(add nuw X, 1), umin(X, Y)) --> select(icmp ult X, Y), 1, 0
+  // sub(umax(add nuw X, 1), umax(X, Y)) --> select(icmp uge X, Y), 1, 0
+  // Also handle the case where the add is replaced with or disjoint.
+  if (auto *MinMax0 = dyn_cast<MinMaxIntrinsic>(Op0)) {
+    if (MinMax0->getIntrinsicID() == MinMax->getIntrinsicID() &&
+        (Op0->hasOneUse() || Op1->hasOneUse())) {
+      Value *A = MinMax0->getLHS();
+      Value *B = MinMax0->getRHS();
+      Value *C = MinMax->getLHS();
+      Value *D = MinMax->getRHS();
+      const APInt *ConstVal;
+      Value *X;
+      // Check if one operand is shared and the other is add/or X, 1 vs X
+      auto MatchPattern = [&](Value *AddOrOp, Value *Other0, Value *XOp,
+                               Value *Other1) -> Instruction * {
+        if (Other0 != Other1)
+          return nullptr;
+        bool IsAdd = match(AddOrOp, m_Add(m_Specific(XOp), m_APInt(ConstVal)));
+        bool IsOr =
+            !IsAdd && match(AddOrOp, m_Or(m_Specific(XOp), m_APInt(ConstVal)));
+        if (!IsAdd && !IsOr)
+          return nullptr;
+        if (*ConstVal != 1)
+          return nullptr;
+        // For add, check NSW/NUW; for or disjoint, it's always safe.
+        if (IsAdd) {
+          auto *Add = cast<BinaryOperator>(AddOrOp);
+          bool IsSigned = MinMax->isSigned();
+          if ((IsSigned && !Add->hasNoSignedWrap()) ||
+              (!IsSigned && !Add->hasNoUnsignedWrap()))
+            return nullptr;
+        } else {
+          auto *Or = cast<PossiblyDisjointInst>(AddOrOp);
+          if (!Or->isDisjoint())
+            return nullptr;
+        }
+        // For i1 type, the transform may not be beneficial; skip.
+        if (Ty->isIntOrIntVectorTy(1))
+          return nullptr;
+        // Create icmp and zext
+        ICmpInst::Predicate Pred = MinMax->getPredicate();
+        Value *Cmp = Builder.CreateICmp(Pred, XOp, Other1);
+        return CastInst::CreateZExtOrBitCast(Cmp, Ty);
+      };
+      if (Instruction *R = MatchPattern(A, B, C, D))
+        return R;
+      if (Instruction *R = MatchPattern(A, B, D, C))
+        return R;
+      if (Instruction *R = MatchPattern(B, A, C, D))
+        return R;
+      if (Instruction *R = MatchPattern(B, A, D, C))
+        return R;
+    }
+  }

   return nullptr;
 }

